import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Switch,
  Typography,
  Alert,
  Snackbar,
  Stack,
  CircularProgress,
  LinearProgress,
  useTheme,
  IconButton
} from '@mui/material';
import { motion } from 'framer-motion';
import { getSettings, updateSettings } from '../services/api';
import {
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon
} from '@mui/icons-material';
import { getCommonStyles } from '../styles/commonStyles';

const Settings = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [settings, setSettings] = useState({
    listenAddr: '',
    listenPort: '',
    enableIPv6: false,
    upstreamDNS: '',
    cacheTTL: '',
    enableDNSSEC: false,
    enableLogging: false,
    enableMetrics: false,
    enableCache: false
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const data = await getSettings();
      setSettings(data);
    } catch (err) {
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field, value) => {
    setSettings(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      await updateSettings(settings);
      setSuccess(true);
    } catch (err) {
      setError('Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                系统设置
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Grid container spacing={1.5}>
        <Grid item xs={12} md={6}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                网络设置
              </Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  label="监听地址"
                  value={settings.listenAddr}
                  onChange={(e) => handleChange('listenAddr', e.target.value)}
                  size="small"
                  sx={styles.textField}
                />
                <TextField
                  fullWidth
                  label="监听端口"
                  value={settings.listenPort}
                  onChange={(e) => handleChange('listenPort', e.target.value)}
                  size="small"
                  sx={styles.textField}
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableIPv6}
                      onChange={(e) => handleChange('enableIPv6', e.target.checked)}
                      size="small"
                      sx={styles.switch}
                    />
                  }
                  label="启用 IPv6"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={6}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                DNS 设置
              </Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  label="上游 DNS"
                  value={settings.upstreamDNS}
                  onChange={(e) => handleChange('upstreamDNS', e.target.value)}
                  size="small"
                  sx={styles.textField}
                />
                <TextField
                  fullWidth
                  label="DNS 缓存时间"
                  value={settings.cacheTTL}
                  onChange={(e) => handleChange('cacheTTL', e.target.value)}
                  size="small"
                  sx={styles.textField}
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableDNSSEC}
                      onChange={(e) => handleChange('enableDNSSEC', e.target.checked)}
                      size="small"
                      sx={styles.switch}
                    />
                  }
                  label="启用 DNSSEC"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                安全设置
              </Typography>
              <Stack spacing={2}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableLogging}
                      onChange={(e) => handleChange('enableLogging', e.target.checked)}
                      size="small"
                      sx={styles.switch}
                    />
                  }
                  label="启用日志记录"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableMetrics}
                      onChange={(e) => handleChange('enableMetrics', e.target.checked)}
                      size="small"
                      sx={styles.switch}
                    />
                  }
                  label="启用指标收集"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableCache}
                      onChange={(e) => handleChange('enableCache', e.target.checked)}
                      size="small"
                      sx={styles.switch}
                    />
                  }
                  label="启用缓存"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end', gap: 1 }}>
        <Button
          variant="contained"
          onClick={handleSave}
          disabled={loading}
          size="small"
          sx={styles.actionButton}
        >
          保存设置
        </Button>
      </Box>
    </Box>
  );
};

export default Settings;
